import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { LoadingSpinner } from "@/components/ui/loading-spinner";
import { useState } from "react";
import { Link } from "react-router-dom";
import { Plan } from "@/types/subscription";

interface SubscriptionConfirmationModalProps {
    isOpen: boolean;
    onClose: () => void;
    onConfirm: () => void;
    plan: Plan | undefined;
    isLoading?: boolean;
}

export function SubscriptionConfirmationModal({
    isOpen,
    onClose,
    onConfirm,
    plan,
    isLoading = false
}: SubscriptionConfirmationModalProps) {
    const [termsAccepted, setTermsAccepted] = useState(false);

    if (!plan) return null;

    const price = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(plan.amount);

    return (
        <Dialog open={isOpen} onOpenChange={(open) => !isLoading && onClose()}>
            <DialogContent className="w-[95vw] md:max-w-md max-h-[90vh] md:max-h-[85vh] p-0 gap-0 rounded-lg border-none shadow-2xl overflow-hidden flex flex-col">
                <DialogHeader className="sticky top-0 z-10 bg-background px-4 md:px-6 pt-4 pb-3 border-b shrink-0">
                    <DialogTitle className="text-xl font-semibold">Confirmar Assinatura</DialogTitle>
                    <DialogDescription className="text-body">
                        Você está prestes a ativar o plano <strong>{plan.name}</strong>.
                    </DialogDescription>
                </DialogHeader>

                <div className="flex-1 overflow-y-auto px-4 md:px-6 py-4 custom-scrollbar space-y-4">
                    <div className="bg-muted/50 p-4 rounded-lg space-y-2">
                        <div className="flex justify-between items-center text-body">
                            <span>Plano</span>
                            <span className="font-medium">{plan.name}</span>
                        </div>
                        <div className="flex justify-between items-center text-body">
                            <span>Valor</span>
                            <span className="font-medium">{price}/mês</span>
                        </div>
                        <div className="flex justify-between items-center text-body text-muted-foreground">
                            <span>Cobrança</span>
                            <span>Imediata</span>
                        </div>
                    </div>

                    <div className="flex items-start space-x-2">
                        <Checkbox
                            id="terms-modal"
                            checked={termsAccepted}
                            onCheckedChange={(checked) => setTermsAccepted(checked as boolean)}
                            className="mt-1"
                        />
                        <div className="grid gap-1.5 leading-none">
                            <label
                                htmlFor="terms-modal"
                                className="text-base md:text-body font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70"
                            >
                                Aceitar os termos
                            </label>
                            <p className="text-body md:text-xs text-muted-foreground mt-1">
                                Li e concordo com os <Link to="/terms" className="text-primary hover:underline" target="_blank">termos de uso</Link> e <Link to="/privacy" className="text-primary hover:underline" target="_blank">política de privacidade</Link>.
                            </p>
                        </div>
                    </div>
                </div>

                <DialogFooter className="sticky bottom-0 z-10 bg-background px-4 md:px-6 pt-3 pb-4 border-t shrink-0 flex flex-col-reverse sm:flex-row sm:justify-end gap-2 sm:gap-3">
                    <Button variant="outline" onClick={onClose} disabled={isLoading} className="w-full sm:w-auto">
                        Cancelar
                    </Button>
                    <Button
                        onClick={onConfirm}
                        disabled={!termsAccepted || isLoading}
                        className="bg-[#CE4836] hover:bg-[#B53C2C] w-full sm:w-auto"
                    >
                        {isLoading && <LoadingSpinner size="sm" inline className="mr-2" />}
                        Confirmar e Assinar
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

