import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { ReactNode, useState } from "react";
import easySalonLogo from "@/assets/easy-logo.svg";

interface AuthLayoutProps {
  children: ReactNode;
  maxWidth?: "md" | "lg" | "xl" | "2xl";
  bannerWidth?: string;
  imagePosition?: string;
}

export const AuthLayout = ({ children, maxWidth = "md", bannerWidth = "lg:w-[60%]", imagePosition = "center" }: AuthLayoutProps) => {
  const [showPrivacyPolicy, setShowPrivacyPolicy] = useState(false);
  const [showTerms, setShowTerms] = useState(false);

  const maxWidthClass = {
    md: "max-w-md",
    lg: "max-w-lg",
    xl: "max-w-xl",
    "2xl": "max-w-2xl",
  }[maxWidth];

  return (
    <div className="h-screen flex overflow-hidden">
      {/* Left Side - Image */}
      <div className={`hidden lg:block ${bannerWidth} relative bg-[#2a1810]`}>
        <div className="relative h-full w-full">
          <img
            src="/lovable-uploads/login-bg.png"
            alt="Easy Salon"
            className="w-full h-full object-cover opacity-75"
            style={{ objectPosition: imagePosition }}
            onError={(e) => { (e.target as HTMLImageElement).style.display = "none"; }}
          />
          <div className="absolute inset-0 bg-black/30" />

          {/* Logo top */}
          <div className="absolute top-8 left-8">
            <img
              src={easySalonLogo}
              alt="Easy Salon"
              className="h-7 w-auto object-contain brightness-0 invert"
            />
          </div>

          {/* Text Overlay */}
          <div className="absolute bottom-20 left-8 right-8">
            <div className="mb-4">
              <h2 className="text-white text-3xl leading-tight font-semibold">
                Agendamentos
              </h2>
              <div className="inline-block bg-primary px-2 py-1 mt-1">
                <span className="text-white text-3xl leading-tight font-semibold">
                  sem complicação
                </span>
              </div>
              <h2 className="text-white text-3xl leading-tight mt-1 font-semibold">
                e uma gestão que funciona.
              </h2>
              <p className="text-white/80 text-lg mt-4">
                Salão&amp;Tecnologia
              </p>
            </div>
          </div>
          <div className="absolute bottom-[5%] left-[5%] right-[5%]">
            <div className="text-white text-body flex items-center bg-black/30 px-4 py-2 rounded-lg backdrop-blur-sm w-fit">
              <button
                onClick={() => setShowPrivacyPolicy(true)}
                className="hover:underline"
              >
                Política de privacidade
              </button>
              <span className="mx-2">|</span>
              <button
                onClick={() => setShowTerms(true)}
                className="hover:underline"
              >
                Termos de uso
              </button>
              <span className="ml-8">v0.0.64</span>
            </div>
          </div>
        </div>
      </div>

      {/* Mobile banner with logo - fixed at top on small screens */}
      <div className="lg:hidden fixed top-0 left-0 right-0 z-50 bg-primary px-6 py-5 flex items-center justify-center">
        <img
          src={easySalonLogo}
          alt="Easy Salon"
          className="h-7 w-auto object-contain brightness-0 invert"
        />
      </div>

      {/* Right Side - Auth Forms */}
      <div className="w-full lg:flex-1 flex flex-col lg:flex-row lg:items-center lg:justify-center h-full overflow-y-auto bg-background px-6 pt-24 pb-8 lg:pt-8 lg:p-8">
        <div className={`w-full ${maxWidthClass} mx-auto my-auto lg:my-0`}>
          {children}
        </div>
      </div>

