    id: string;
    name: string;
    phone: string;
  } | null;
  professionalId?: string;
  onClose?: () => void;
}

const GOLD = "#A8926A"
const DARK = "#4A2E1A"
const RED = "#CE4836"
const BEIGE = "#EFE9DD"
const BANNER = "#E8DECA"
const JAKARTA = "'Plus Jakarta Sans', system-ui, sans-serif"

function SnowSVG({ size, top, left, right, bottom, opacity = 0.25 }: {
  size: number
  top?: number | string
  left?: number | string
  right?: number | string
  bottom?: number | string
  opacity?: number
}) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      style={{ position: "absolute", top, left, right, bottom, opacity, pointerEvents: "none", flexShrink: 0 }}
    >
      <line x1="12" y1="2" x2="12" y2="22" stroke={GOLD} strokeWidth="1.5" strokeLinecap="round" />
      <line x1="2" y1="12" x2="22" y2="12" stroke={GOLD} strokeWidth="1.5" strokeLinecap="round" />
      <line x1="4.93" y1="4.93" x2="19.07" y2="19.07" stroke={GOLD} strokeWidth="1.5" strokeLinecap="round" />
      <line x1="19.07" y1="4.93" x2="4.93" y2="19.07" stroke={GOLD} strokeWidth="1.5" strokeLinecap="round" />
    </svg>
  )
}

function Dot({ top, left, right, bottom }: { top?: number; left?: number; right?: number; bottom?: number }) {
  return (
    <div style={{
      position: "absolute",
      width: 5,
      height: 5,
      borderRadius: "50%",
      background: GOLD,
      opacity: 0.3,
      top,
      left,
      right,
      bottom,
      pointerEvents: "none",
    }} />
  )
}

export function FirstAppointmentModal({ testClient, professionalId }: FirstAppointmentModalProps) {
  const navigate = useNavigate();
  const { selectedSalon } = useSelectedSalon();

  useEffect(() => {
    analytics.trackEvent('onboarding_first_appointment_modal_viewed', {
      has_test_client: !!testClient
    });
