  const handleActionClick = () => {
    analytics.trackEvent('onboarding_first_appointment_clicked', {
      test_client_id: testClient?.id || null
    });

    // Navega para a agenda passando o estado para abertura automática do modal
    navigate('/salon/agenda', {
